import{_ as e,p as i,q as d,a1 as l}from"./framework-5866ffd3.js";const s={},r=l('<h1 id="redis" tabindex="-1"><a class="header-anchor" href="#redis" aria-hidden="true">#</a> Redis</h1><h2 id="如何保持redis与mysql数据一致性" tabindex="-1"><a class="header-anchor" href="#如何保持redis与mysql数据一致性" aria-hidden="true">#</a> 如何保持redis与mysql数据一致性：</h2><p>双删策略</p><ol><li><p>先删缓存</p></li><li><p>再写入mysql</p></li><li><p>等待时间（500ms），再删除缓存。</p><ul><li>此时删除的是写入mysql数据时，读行为在redis中产生的脏数据。产生的原因：第一次删除后，缓存中读不到数据，线程从mysql中将数据写入缓存，此时新数据还未写入mysql。</li></ul></li></ol><h2 id="redis事务" tabindex="-1"><a class="header-anchor" href="#redis事务" aria-hidden="true">#</a> redis事务</h2><p>redis事务是一组命令的集合，redis事务是非原子性的</p><ul><li>开始事务：使用<code>MULIT</code>开始事务，将后续命令放入队列中。</li><li>提交事务：使用<code>EXEC</code>提交事务，此时开始串行化执行队列中的命令。</li><li>非原子性：redis事务中命令是串行化执行，但事务整体不是原子性的。</li></ul><p>事务其他命令：</p><ul><li>取消事务：<code>DISCARD</code>，取消事务中的所有命令</li><li>监视事务中的key：<code>WATCH</code>，如果事务开始前，key被其他命令执行，则中断事务，不执行事务中的所有命令。</li><li>取消监视：<code>UNWATCH</code></li></ul>',9),a=[r];function c(o,t){return i(),d("div",null,a)}const n=e(s,[["render",c],["__file","Redis.html.vue"]]);export{n as default};
